     1→"use client";
     2→
     3→import { useState, Suspense } from "react";
     4→import { useSearchParams } from "next/navigation";
     5→import useSWR from "swr";
     6→import Link from "next/link";
     7→import {
     8→  semanticReleases as srApi,
     9→  projects as projectsApi,
    10→} from "@/lib/api/client";
    11→import { VersionChip } from "@/components/ui/version-chip";
    12→import { ConfirmDialog } from "@/components/ui/confirm-dialog";
    13→import { Trash2 } from "lucide-react";
    14→import { timeAgo } from "@/lib/format";
    15→import type { Project, SemanticRelease } from "@/lib/api/types";
    16→
    17→/* ---------- Urgency chip ---------- */
    18→
    19→const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    20→  critical: { bg: "#dc2626", text: "#ffffff" },
    21→  high: { bg: "#f97316", text: "#ffffff" },
    22→};
    23→
    24→function UrgencyChip({ urgency }: { urgency: string }) {
    25→  const u = urgency.toLowerCase();
    26→  const style = URGENCY_COLORS[u];
    27→  if (!style) return null;
    28→  return (
    29→    <span
    30→      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
    31→      style={{ backgroundColor: style.bg, color: style.text }}
    32→    >
    33→      {urgency}
    34→    </span>
    35→  );
    36→}
    37→
    38→/* ---------- Helpers ---------- */
    39→
    40→function truncate(str: string, max: number): string {
    41→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    42→}
    43→
    44→const PER_PAGE = 15;
    45→
    46→/* ---------- Main component ---------- */
    47→
    48→export function SemanticReleasesList() {
    49→  return (
    50→    <Suspense>
    51→      <SemanticReleasesListInner />
    52→    </Suspense>
    53→  );
    54→}
    55→
    56→function SemanticReleasesListInner() {
    57→  const searchParams = useSearchParams();
    58→  const initialProject = searchParams.get("project") ?? "all";
    59→  const [page, setPage] = useState(1);
    60→  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
    61→  const [deletingId, setDeletingId] = useState<string | null>(null);
    62→
    63→  /* Fetch projects for the filter dropdown */
    64→  const { data: projectsData } = useSWR("projects-for-sr-filter", () =>
    65→    projectsApi.list()
    66→  );
    67→  const projectsById = new Map<string, Project>();
    68→  for (const p of projectsData?.data ?? []) projectsById.set(p.id, p);
    69→
    70→  /* Fetch semantic releases — scoped by project or all */
    71→  const { data: scopedData, isLoading: scopedLoading, mutate: mutateScopedData } = useSWR(
    72→    projectFilter !== "all" ? ["sr-scoped", page, projectFilter] : null,
    73→    () => srApi.list(projectFilter, page, PER_PAGE)
    74→  );
    75→
    76→  const { data: allData, isLoading: allLoading, mutate: mutateAllData } = useSWR(
    77→    projectFilter === "all" ? ["sr-all", page] : null,
    78→    () => srApi.listAll(page, PER_PAGE)
    79→  );
    80→
    81→  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
    82→  const releases: SemanticRelease[] =
    83→    projectFilter !== "all"
    84→      ? scopedData?.data ?? []
    85→      : allData?.data ?? [];
    86→
    87→  const mutateData = projectFilter !== "all" ? mutateScopedData : mutateAllData;
    88→
    89→  /* Pagination math */
    90→  const activeData = projectFilter !== "all" ? scopedData : allData;
    91→  const total = activeData?.meta?.total ?? 0;
    92→  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
    93→  const startRow = (page - 1) * PER_PAGE + 1;
    94→  const endRow = Math.min(page * PER_PAGE, total);
    95→
    96→  return (
    97→    <div className="space-y-6 fade-in">
    98→      {/* Page title */}
    99→      <h1
   100→        style={{
   101→          fontFamily: "var(--font-fraunces)",
   102→          fontSize: "24px",
   103→          fontWeight: 700,
   104→          color: "#111113",
   105→        }}
   106→      >
   107→        Semantic Releases
   108→      </h1>
   109→
   110→      {/* Project filter */}
   111→      <div>
   112→        <select
   113→          value={projectFilter}
   114→          onChange={(e) => {
   115→            setProjectFilter(e.target.value);
   116→            setPage(1);
   117→          }}
   118→          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
   119→          style={{
   120→            fontFamily: "var(--font-dm-sans)",
   121→            fontSize: "13px",
   122→            color: "#111113",
   123→            border: "1px solid #e8e8e5",
   124→          }}
   125→          onFocus={(e) =>
   126→            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
   127→          }
   128→          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   129→        >
   130→          <option value="all">All Projects</option>
   131→          {projectsData?.data.map((p: Project) => (
   132→            <option key={p.id} value={p.id}>
   133→              {p.name}
   134→            </option>
   135→          ))}
   136→        </select>
   137→      </div>
   138→
   139→      {/* Table card */}
   140→      <div
   141→        className="overflow-hidden rounded-lg bg-white"
   142→        style={{ border: "1px solid #e8e8e5" }}
   143→      >
   144→        {isLoading ? (
   145→          <div
   146→            className="py-16 text-center"
   147→            style={{
   148→              fontFamily: "var(--font-dm-sans)",
   149→              fontSize: "13px",
   150→              color: "#6b7280",
   151→            }}
   152→          >
   153→            Loading...
   154→          </div>
   155→        ) : releases.length === 0 ? (
   156→          <div className="py-16 text-center">
   157→            <p
   158→              style={{
   159→                fontFamily: "var(--font-fraunces)",
   160→                fontStyle: "italic",
   161→                fontSize: "15px",
   162→                color: "#9ca3af",
   163→              }}
   164→            >
   165→              No semantic releases yet
   166→            </p>
   167→          </div>
   168→        ) : (
   169→          <table className="w-full">
   170→            <thead>
   171→              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   172→                {["Project", "Version", "Status", "Urgency", "Age", ""].map(
   173→                  (col) => (
   174→                    <th
   175→                      key={col}
   176→                      className="px-4 py-3 text-left"
   177→                      style={{
   178→                        fontFamily: "var(--font-dm-sans)",
   179→                        fontSize: "11px",
   180→                        fontWeight: 600,
   181→                        textTransform: "uppercase" as const,
   182→                        letterSpacing: "0.08em",
   183→                        color: "#9ca3af",
   184→                      }}
   185→                    >
   186→                      {col}
   187→                    </th>
   188→                  )
   189→                )}
   190→              </tr>
   191→            </thead>
   192→            <tbody>
   193→              {releases.map((sr) => {
   194→                const project = projectsById.get(sr.project_id);
   195→                return (
   196→                  <tr
   197→                    key={sr.id}
   198→                    className="transition-colors hover:bg-[#fafaf9]"
   199→                    style={{ borderBottom: "1px solid #e8e8e5" }}
   200→                  >
   201→                    {/* Project */}
   202→                    <td className="px-4 py-3">
   203→                      {project ? (
   204→                        <Link
   205→                          href={`/projects/${project.id}`}
   206→                          className="hover:underline"
   207→                          style={{
   208→                            fontFamily: "var(--font-dm-sans)",
   209→                            fontSize: "13px",
   210→                            color: "#111113",
   211→                            fontWeight: 500,
   212→                          }}
   213→                        >
   214→                          {project.name}
   215→                        </Link>
   216→                      ) : (
   217→                        <span
   218→                          style={{
   219→                            fontFamily: "var(--font-dm-sans)",
   220→                            fontSize: "13px",
   221→                            color: "#9ca3af",
   222→                          }}
   223→                        >
   224→                          {"\u2014"}
   225→                        </span>
   226→                      )}
   227→                    </td>
   228→
   229→                    {/* Version */}
   230→                    <td className="px-4 py-3">
   231→                      <Link href={`/projects/${sr.project_id}/semantic-releases/${sr.id}`}>
   232→                        <VersionChip version={sr.version} />
   233→                      </Link>
   234→                    </td>
   235→
   236→                    {/* Status */}
   237→                    <td className="px-4 py-3">
   238→                      <span
   239→                        className="text-[13px] font-medium"
   240→                        style={{
   241→                          fontFamily: "var(--font-dm-sans)",
   242→                          color: sr.status === "completed" ? "#16a34a" : "#e8601a",
   243→                        }}
   244→                      >
   245→                        {sr.status}
   246→                      </span>
   247→                    </td>
   248→
   249→                    {/* Urgency */}
   250→                    <td className="px-4 py-3">
   251→                      {sr.report?.urgency ? (
   252→                        <UrgencyChip urgency={sr.report.urgency} />
   253→                      ) : (
   254→                        <span
   255→                          style={{
   256→                            fontFamily: "var(--font-dm-sans)",
   257→                            fontSize: "13px",
   258→                            color: "#9ca3af",
   259→                          }}
   260→                        >
   261→                          {"\u2014"}
   262→                        </span>
   263→                      )}
   264→                    </td>
   265→
   266→                    {/* Age */}
   267→                    <td className="px-4 py-3">
   268→                      <span
   269→                        style={{
   270→                          fontFamily: "var(--font-dm-sans)",
   271→                          fontSize: "13px",
   272→                          color: "#9ca3af",
   273→                        }}
   274→                      >
   275→                        {timeAgo(sr.completed_at ?? sr.created_at)}
   276→                      </span>
   277→                    </td>
   278→
   279→                    {/* Delete */}
   280→                    <td className="px-4 py-3">
   281→                      <button
   282→                        onClick={() => setDeletingId(sr.id)}
   283→                        className="rounded p-1 transition-colors hover:bg-red-50 hover:text-red-600"
   284→                        style={{ color: "#9ca3af" }}
   285→                        title="Delete semantic release"
   286→                      >
   287→                        <Trash2 className="h-4 w-4" />
   288→                      </button>
   289→                    </td>
   290→                  </tr>
   291→                );
   292→              })}
   293→            </tbody>
   294→          </table>
   295→        )}
   296→      </div>
   297→
   298→      {/* Pagination */}
   299→      {total > 0 && (
   300→        <div className="flex items-center justify-between">
   301→          <span
   302→            style={{
   303→              fontFamily: "var(--font-dm-sans)",
   304→              fontSize: "13px",
   305→              color: "#9ca3af",
   306→            }}
   307→          >
   308→            {startRow}&ndash;{endRow} of {total}
   309→          </span>
   310→          <div className="flex items-center gap-2">
   311→            <button
   312→              disabled={page <= 1}
   313→              onClick={() => setPage(page - 1)}
   314→              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
